    adj: dict = spec["adj"];
    vals: dict = spec["vals"];
    seen: set = set();
    frontier: list = [spec["start"]];
    while frontier {
        n = frontier.pop();
        if n not in seen {
            seen.add(n);
            frontier.extend(adj[n]);
        }
    }
    total: int = sum([vals[n] for n in seen]);
    leaves: list = sorted([vals[n] for n in seen if not adj[n]], reverse=True);
    got: int = 0;
    used: int = 0;
    for v in leaves {
        if got * 2 >= total { break; }
        got += v;
        used += 1;
    }
    return used if got * 2 >= total else -1;
}

