def mutual_follow_pairs(spec: dict) -> list:
    """List every mutual-follow pair as 'a|b' with a < b, sorted."""
    users = set(spec["users"])
    fset = {(f[0], f[1]) for f in spec["follows"] if f[0] in users and f[1] in users}
    return sorted(a + "|" + b for a, b in fset if a < b and (b, a) in fset)

