    can start with Book entry { visit [-->][?:Visitor]; }
    can grab with Visitor entry { self.msgs.append(here.message); }
    can pick with exit {
        self.msgs.sort();
        for m in self.msgs { if len(m) > len(self.best) { self.best = m; } }
    }
