def count_ext(spec: dict) -> int:
    """Count files across all folders whose name ends with the extension."""
    total = 0
    for folder in spec["folders"]:
        for fname, size in folder["files"]:
            if fname.endswith(spec["ext"]):
                total += 1
    return total

