def dead_pages(spec: dict) -> int:
    """Count pages with no outgoing links (dead ends)."""
    pages = set(spec["pages"])
    sources = set()
    for src, dst in spec["links"]:
        if src in pages and dst in pages:
            sources.add(src)
    n = 0
    for p in spec["pages"]:
        if p not in sources:
            n += 1
    return n

