def dead_pages(spec: dict) -> int {
    site = Site();
    pnodes: dict = {};
    for p in spec["pages"] {
        pg = Page(name=str(p));
        site +>:Contains:+> pg;
        pnodes[p] = pg;
    }
    for lk in spec["links"] {
        if lk[0] in pnodes and lk[1] in pnodes {
            pnodes[lk[0]] +>:LinksTo:+> pnodes[lk[1]];
        }
    }
    return (site spawn DeadEnds()).n;
}

